mapper.select:
SELECT c.id, c.name, c.subject_id AS subjectId, s.name AS subjectName, c.state, c.price, c.unit_price AS unitPrice, c.discount, c.lesson_count AS lessonCount, c.lesson_type AS lessonType, c.cover, c.for_sale AS forSale, c.bookable, c.recommend, c.storage, c.add_time AS addTime FROM course c LEFT JOIN subject s ON c.subject_id = s.id AND s.deleted = 0 WHERE c.deleted = 0
AND c.name LIKE CONCAT('%', #{query.name}, '%')
AND c.subject_id = #{query.subjectId}
AND c.state = #{query.state}
AND c.lesson_type = #{query.lessonType}
AND c.for_sale = #{query.forSale}
AND c.grade_names LIKE CONCAT('%', #{query.gradeName}, '%')
ORDER BY c.add_time DESC

SELECT c.id, c.name, s.name AS subjectName, CASE c.state WHEN 1 THEN '启用' ELSE '禁用' END AS stateText, c.price, c.unit_price AS unitPrice, c.discount, c.lesson_count AS lessonCount, CASE c.lesson_type WHEN 1 THEN '大课' WHEN 2 THEN '小班课' WHEN 3 THEN '一对一' ELSE '未知' END AS lessonTypeText, CASE c.for_sale WHEN 1 THEN '是' ELSE '否' END AS forSaleText, CASE c.bookable WHEN 1 THEN '是' ELSE '否' END AS bookableText, c.storage FROM course c LEFT JOIN subject s ON c.subject_id = s.id AND s.deleted = 0 WHERE c.deleted = 0
AND c.name LIKE CONCAT('%', #{query.name}, '%')
AND c.subject_id = #{query.subjectId}
AND c.state = #{query.state}
AND c.lesson_type = #{query.lessonType}
AND c.for_sale = #{query.forSale}
ORDER BY c.add_time DESC
